import React, { useState, useMemo } from 'react';
import { DataConnection, BuilderPage } from '../../types';

interface CodeEditorProps {
  builderPages: BuilderPage[];
  activeBuilderPageId: string;
  dataConnections: DataConnection;
  onBuilderPagesChange: (pages: BuilderPage[]) => void;
}

const CodeEditor: React.FC<CodeEditorProps> = ({
  builderPages,
  activeBuilderPageId,
  dataConnections,
  onBuilderPagesChange
}) => {
  const [selectedWindow, setSelectedWindow] = useState<string | null>(null);

  // Helper functions with memoization
  const getCurrentBuilderPage = useMemo((): BuilderPage => {
    return builderPages.find(p => p.id === activeBuilderPageId) || builderPages[0];
  }, [builderPages, activeBuilderPageId]);

  const windows = useMemo(() => getCurrentBuilderPage.windows, [getCurrentBuilderPage]);

  const selectedWindowData = useMemo(() => {
    return selectedWindow ? windows.find(w => w.id === selectedWindow) : null;
  }, [windows, selectedWindow]);

  // Handle window code update
  const handleCodeChange = (code: string) => {
    if (!selectedWindow) return;
    
    const updatedPages = builderPages.map(page => {
      if (page.id !== activeBuilderPageId) return page;
      
      return {
        ...page,
        windows: page.windows.map(window => {
          if (window.id !== selectedWindow) return window;
          return { ...window, jsCode: code };
        })
      };
    });
    
    onBuilderPagesChange(updatedPages);
  };

  return (
    <div style={{ 
      flex: 1, 
      backgroundColor: '#ffffff',
      fontFamily: '"Segoe UI", "Arial", sans-serif',
      display: 'flex',
      height: '100%',
      color: '#495057'
    }}>
      {/* Left Panel - Window List */}
      <div style={{
        width: '220px',
        backgroundColor: '#f8f9fa',
        borderRight: '1px solid #dee2e6',
        display: 'flex',
        flexDirection: 'column',
        padding: '12px',
        overflow: 'auto'
      }}>
        <h3 style={{ margin: '0 0 12px 0', fontSize: '13px', fontWeight: '600', color: '#495057', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
          Windows
        </h3>
        
        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
          {windows.map(window => (
            <div
              key={window.id}
              onClick={() => setSelectedWindow(window.id)}
              style={{
                padding: '8px 10px',
                backgroundColor: selectedWindow === window.id ? '#e3f2fd' : '#ffffff',
                border: selectedWindow === window.id ? '1px solid #0066cc' : '1px solid #dee2e6',
                borderRadius: '3px',
                cursor: 'pointer',
                fontSize: '12px',
                transition: 'all 0.2s ease',
                color: selectedWindow === window.id ? '#0066cc' : '#495057'
              }}
              onMouseEnter={(e) => {
                if (selectedWindow !== window.id) {
                  e.currentTarget.style.backgroundColor = '#f0f0f0';
                }
              }}
              onMouseLeave={(e) => {
                if (selectedWindow !== window.id) {
                  e.currentTarget.style.backgroundColor = '#ffffff';
                }
              }}
            >
              <div style={{ fontWeight: '500', marginBottom: '2px' }}>
                {window.title}
              </div>
              <div style={{ fontSize: '10px', color: '#6c757d' }}>
                {window.type}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Middle Panel - Code Execution */}
      <div style={{
        flex: 1,
        backgroundColor: '#ffffff',
        borderRight: '1px solid #dee2e6',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden'
      }}>
        <div style={{
          padding: '8px 12px',
          backgroundColor: '#f8f9fa',
          borderBottom: '1px solid #dee2e6',
          fontSize: '12px',
          fontWeight: '500',
          color: '#495057'
        }}>
          {selectedWindowData ? `Execution: ${selectedWindowData.title}` : 'Select a window'}
        </div>
        
        <div key={selectedWindowData?.id} style={{
          flex: 1,
          overflow: 'auto',
          backgroundColor: '#ffffff',
          padding: '0'
        }}>
          {selectedWindowData && (
            <WindowContentRenderer window={selectedWindowData} dataConnections={dataConnections} />
          )}
        </div>
      </div>

      {/* Right Panel - Code Editor */}
      <div style={{
        width: '380px',
        backgroundColor: '#ffffff',
        display: 'flex',
        flexDirection: 'column',
        borderLeft: '1px solid #dee2e6'
      }}>
        <div style={{
          padding: '8px 12px',
          backgroundColor: '#f8f9fa',
          borderBottom: '1px solid #dee2e6',
          fontSize: '12px',
          fontWeight: '500',
          color: '#495057'
        }}>
          Code Editor
        </div>
        
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
          {selectedWindowData ? (
            <textarea
              value={selectedWindowData.jsCode || ''}
              onChange={(e) => handleCodeChange(e.target.value)}
              style={{
                flex: 1,
                border: 'none',
                padding: '12px',
                fontSize: '12px',
                fontFamily: '"Courier New", monospace',
                backgroundColor: '#ffffff',
                color: '#495057',
                resize: 'none',
                outline: 'none'
              }}
            />
          ) : (
            <div style={{
              flex: 1,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#6c757d',
              fontSize: '12px'
            }}>
              Select a window to edit code
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// Separate component to render just the window content
const WindowContentRenderer: React.FC<{
  window: any;
  dataConnections: DataConnection;
}> = ({ window, dataConnections }) => {
  if (window.type === 'javascript') {
    return <JavaScriptWindowRenderer window={window} dataConnections={dataConnections} />;
  } else if (window.type === 'html') {
    return <HtmlWindowRenderer window={window} />;
  } else if (window.type === 'visualization') {
    return <VisualizationWindowRenderer window={window} />;
  }
  return null;
};

// JavaScript window renderer
const JavaScriptWindowRenderer: React.FC<{
  window: any;
  dataConnections: DataConnection;
}> = ({ window, dataConnections }) => {
  const contentRef = React.useRef<HTMLDivElement>(null);

  React.useEffect(() => {
    if (!contentRef.current) return;

    try {
      const globalVariables = dataConnections.globalVariables || {};
      const apiVariables: Record<string, any> = {};

      const sandboxDocument = {
        getElementById: (id: string) => contentRef.current?.querySelector(`#${id}`),
        querySelector: (selector: string) => contentRef.current?.querySelector(selector),
        querySelectorAll: (selector: string) => contentRef.current?.querySelectorAll(selector),
        createElement: (tag: string) => document.createElement(tag),
      };

      const sandboxWindow = {
        alert: alert,
        console,
      };

      const globalVarNames = Object.keys(globalVariables);
      const globalVarValues = globalVarNames.map(name => globalVariables[name]);
      const apiVarNames = Object.keys(apiVariables);
      const apiVarValues = apiVarNames.map(name => apiVariables[name]);

      const allParamNames = ['document', 'window', 'globalVariables', 'apiVariables', ...globalVarNames, ...apiVarNames];
      const allParamValues = [sandboxDocument, sandboxWindow, globalVariables, apiVariables, ...globalVarValues, ...apiVarValues];

      const func = new Function(...allParamNames, window.jsCode || '');
      func(...allParamValues);
    } catch (error) {
      if (contentRef.current) {
        contentRef.current.innerHTML = `<div style="color: red; padding: 10px; font-family: monospace; white-space: pre-wrap;">Error: ${String(error)}</div>`;
      }
    }
  }, [window.jsCode, dataConnections]);

  return <div ref={contentRef} style={{ width: '100%', height: '100%' }} />;
};

// HTML window renderer
const HtmlWindowRenderer: React.FC<{ window: any }> = ({ window }) => {
  return (
    <div style={{ width: '100%', height: '100%', overflow: 'auto' }}>
      <iframe
        srcDoc={window.content || ''}
        style={{
          width: '100%',
          height: '100%',
          border: 'none'
        }}
      />
    </div>
  );
};

// Visualization window renderer
const VisualizationWindowRenderer: React.FC<{ window: any }> = ({ window }) => {
  return (
    <div style={{
      width: '100%',
      height: '100%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: '#f8f9fa'
    }}>
      {window.imageData ? (
        <img 
          src={window.imageData} 
          style={{
            maxWidth: '100%',
            maxHeight: '100%',
            objectFit: 'contain'
          }}
          alt=""
        />
      ) : (
        <div style={{ color: '#6c757d' }}>No image loaded</div>
      )}
    </div>
  );
};

export default CodeEditor;
